set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AI 短剧 (AI 微短剧)"
TOPIC="Evidence"

usage() {
  cat <<EOF
evidence.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 8 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./evidence.sh             # interactive
  ./evidence.sh --dry-run   # walk through but no file
  ./evidence.sh --json      # JSON to stdout
  ./evidence.sh --explain   # show backing playbook rules + mental models
  ./evidence.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Evidence 主题下的 playbook 规则组合成交互树。

基于 8 条规则:
  • 如果 一致性先稳静帧、再驱动运动 → 则 ：先抠稳 3-5 张角色/场景关键帧 →「参考图 + 提示词约束 + 固定 Seed」拉到 95%+ → 首尾帧串联 →
  • 如果 一致性按"主体类型"选工具，不按品牌 → 则 ：单主角→可灵 omni/即梦参考；多主体→Vidu(多主体参考生)；真人形象→Wan2.6/Runway Act-Tw
  • 如果 优先做 AI 漫剧，真人 AI 剧只在天花板需求时做 → 则 ：漫剧(动画风)一致性更可控、ROI 最高(约 1.15-1.2)；真人 AI 剧审美天花板高但恐怖谷/崩脸风险大。案例
  • 如果 国内走投流：先合规、3 日 ROI 达标才放量 → 则 ：合规闸门过了再投，3 日 ROI 约 110-120% 才加预算。案例：小程序短剧测试期 ROI 仅 90% → 不放
  • 如果 出海把 AI 用在译制降本而非纯生成 → 则 ：字幕/配音/换脸三层本地化，一剧多语；变现走订阅/单集解锁。案例：一部国内成片用 AI 译制成英/西/印尼三语上 Re
