  • 如果 别信"1:1 复刻/商用级稳定/全球首个"营销，按实测打折先小批测 → 则 ：所有厂商一致性宣称都要用自己的素材小批验证。案例：某工具宣称"1:1 复刻五官"，实测多主体仍崩 → 仅用于单主角镜头
  • 如果 选题对标爆款 + 守网文爽点，AI 不改叙事规律 → 则 ：强冲突/强反转/3 秒留人/前 3 集钩子，AI 只换生产方式不换爽感逻辑。案例：把一个数据验证过的爽文设定用 AI 

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "一致性先稳静帧、再驱动运动"
  "一致性按\"主体类型\"选工具，不按品牌"
  "优先做 AI 漫剧，真人 AI 剧只在天花板需求时做"
  "国内走投流：先合规、3 日 ROI 达标才放量"
  "出海把 AI 用在译制降本而非纯生成"
  "工具按瓶颈组合"
  "别信\"1:1 复刻/商用级稳定/全球首个\"营销，按实测打折先小批测"
  "选题对标爆款 + 守网文爽点，AI 不改叙事规律"
)
declare -a RULE_ACTIONS=(
  "：先抠稳 3-5 张角色/场景关键帧 →「参考图 + 提示词约束 + 固定 Seed」拉到 95%+ → 首尾帧串联 → 仍崩就上 LoRA。案例：一个古装女主多场景，先定 5 张标准角色图入库，每镜带参考图生成，脸稳后再加运镜。evidence: [T03-S002, T02-S001]"
  "：单主角→可灵 omni/即梦参考；多主体→Vidu(多主体参考生)；真人形象→Wan2.6/Runway Act-Two；风格化角色→MJ --cref。案例：双人对手戏脸总串 → 换 Vidu 多主体参考，崩坏率显著下降。evidence: [T02-S001, T02-S003]"
  "：漫剧(动画风)一致性更可控、ROI 最高(约 1.15-1.2)；真人 AI 剧审美天花板高但恐怖谷/崩脸风险大。案例：新团队首部作品选漫剧跑通工作流与回收，再挑战真人。evidence: [T06-S001, T02-S001]"
  "：合规闸门过了再投，3 日 ROI 约 110-120% 才加预算。案例：小程序短剧测试期 ROI 仅 90% → 不放量，回炉改钩子前 3 集。evidence: [T03-S010, T04-S010]"
  "：字幕/配音/换脸三层本地化，一剧多语；变现走订阅/单集解锁。案例：一部国内成片用 AI 译制成英/西/印尼三语上 ReelShort，成本仅原制作的零头。evidence: [T03-S012, T01-S004]"
  "：国内 = 即梦/可灵/Vidu + 豆包/DeepSeek 脚本 + TTS + 剪映；出海加 Runway/Sora/Luma/PixVerse + ElevenLabs + HeyGen(多语对口型)。案例：出海项目口型对不上多语配音 → 接 HeyGen 重做对口型。evidence: [T02-S004, T02-S006]"
  "：所有厂商一致性宣称都要用自己的素材小批验证。案例：某工具宣称\"1:1 复刻五官\"，实测多主体仍崩 → 仅用于单主角镜头。evidence: [T02-S002, T06-S004]"
  "：强冲突/强反转/3 秒留人/前 3 集钩子，AI 只换生产方式不换爽感逻辑。案例：把一个数据验证过的爽文设定用 AI 漫剧重制，比原创新设定更稳。evidence: [T04-S001, T06-S002]"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "evidence-decision"
fi
